def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
  val n = online.length
  if (n == 0) return -1L

  val adj = Array.ofDim[(Int, Long)](n)
  val inDegree = Array.fill(n)(0)
  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    val cost = edge(2)
    adj(u) = adj(u) :+ (v, cost)
    inDegree(v) += 1
  }

  val q = scala.collection.mutable.Queue[Int]()
  for (i <- 0 until n) {
    if (inDegree(i) == 0) q.enqueue(i)
  }

  val topologicalOrder = scala.collection.mutable.ListBuffer[Int]()
  while (q.nonEmpty) {
    val u = q.dequeue()
    topologicalOrder += u
    for ((v, cost) <- adj(u)) {
      inDegree(v) -= 1
      if (inDegree(v) == 0) q.enqueue(v)
    }
  }

  val maxEdge = if (edges.isEmpty) 0 else edges.map(_(2)).max
  var low = 0L
  var high = maxEdge
  var answer = -1L

  while (low <= high) {
    val mid = (low + high) / 2
    val dist = Array.fill(n)(Long.MaxValue)
    dist(0) = 0L
    for (u <- topologicalOrder) {
      if (!online(u)) continue
      for ((v, cost) <- adj(u)) {
        if (cost >= mid && online(v)) {
          if (dist(u) + cost < dist(v)) {
            dist(v) = dist(u) + cost
          }
        }
      }
    }
    if (dist(n-1) <= k) {
      answer = mid
      low = mid + 1
    } else {
      high = mid - 1
    }
  }

  answer
}
