using namespace std;

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<pair<int, long long>>> adj(n);
    vector<long long> in_degree(n, 0);
    for (auto& edge : edges) {
        int u = edge[0];
        int v = edge[1];
        long long cost = edge[2];
        adj[u].push_back({v, cost});
        in_degree[v]++;
    }

    vector<int> topological_order;
    queue<int> q;
    for (int i = 0; i < n; ++i) {
        if (in_degree[i] == 0) {
            q.push(i);
        }
    }
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        topological_order.push_back(u);
        for (auto& [v, cost] : adj[u]) {
            in_degree[v]--;
            if (in_degree[v] == 0) {
                q.push(v);
            }
        }
    }

    long long max_cost = 0;
    for (auto& edge : edges) {
        max_cost = max(max_cost, edge[2]);
    }

    long long low = 0, high = max_cost;
    long long answer = -1;

    while (low <= high) {
        long long mid = (low + high) / 2;
        vector<long long> dist(n, LLONG_MAX);
        dist[0] = 0;
        for (int u : topological_order) {
            if (!online[u]) continue;
            for (auto& [v, cost] : adj[u]) {
                if (cost >= mid && online[v]) {
                    if (dist[u] + cost < dist[v]) {
                        dist[v] = dist[u] + cost;
                    }
                }
            }
        }
        if (dist[n-1] <= k) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}
