import scala.collection.mutable

def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
  val n = online.length
  val adj = Array.fill(n)(mutable.ListBuffer[(Int, Long)]())
  val in_degree = Array.fill(n)(0)
  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    val cost = edge(2)
    adj(u) += (v, cost)
    in_degree(v) += 1
  }

  val q = mutable.Queue[Int]()
  for (i <- 0 until n) {
    if (in_degree(i) == 0) q += i
  }
  val topologicalOrder = mutable.ListBuffer[Int]()
  while (q.nonEmpty) {
    val u = q.dequeue()
    topologicalOrder += u
    for ((v, cost) <- adj(u)) {
      in_degree(v) -= 1
      if (in_degree(v) == 0) q += v
    }
  }

  val maxEdge = edges.map(_.apply(2)).max

  var low = 0L
  var high = maxEdge
  var answer = -1L

  while (low <= high) {
    val mid = (low + high) / 2
    val dist = Array.fill(n)(Long.MaxValue)
    dist(0) = 0L
    for (u <- topologicalOrder) {
