def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
  val n = online.length
  val adj = Array.ofDim[Array[(Int, Long)]](n)
  val inDegree = Array.fill(n)(0)

  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    val cost = edge(2)
    adj(u) = adj(u) :+ (v, cost)
    inDegree(v) += 1
  }

  val queue = scala.collection.mutable.Queue[Int]()
  for (i <- 0 until n) {
    if (inDegree(i) == 0) queue += i
  }

  val topologicalOrder = scala.collection.mutable.ListBuffer[Int]()
  while (queue.nonEmpty) {
    val u = queue.dequeue()
    topologicalOrder += u
    for ((v, cost) <- adj(u)) {
      inDegree(v) -= 1
      if (inDegree(v) == 0) queue += v
    }
  }

  val maxEdgeCost = if (edges.isEmpty) 0 else edges.map(_.last).max
  var low = 0L
  var high = maxEdgeCost
  var answer = -1L

  while (low <= high) {
    val mid = (low + high) / 2
    val dist = Array.fill(n)(Long.MaxValue)
