    queue<int> q;
    for (int i = 0; i < n; ++i) {
        if (in_degree[i] == 0) {
            q.push(i);
        }
    }
    while (!q.empty()) {
        int u = q.front();
        q.pop();
        topological_order.push_back(u);
        for (auto& [v, cost] : adj[u]) {
            in_degree[v]--;
            if (in_degree[v] == 0) {
